//                                                                                 ||//                         بِسْمِ ٱللّٰهِ ٱلرَّحْمٰنِ ٱلرَّحِيمِ                                       ||// "وَلَقَدْ خَلَقْنَا الْإِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِ نَفْسُهُ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ" (Quran 50:16) -     ||//                                                                                 ||#include<bits/stdc++.h>using namespace std; int main(){    ios_base::sync_with_stdio(0);    cin.tie(NULL);    int test;    cin >> test;    while(test--){        int n,x;        cin >> n >> x;        vector <int> vec(n);        int mn = 0,min1=0;        for(int i =0;i<n;i++){            cin >> vec[i];            if(i==0){min1=vec[i];}            if(i>0){                min1 = vec[i]-vec[i-1];             }             mn = max(mn,min1);            if(i==n-1){                min1 = (x-vec[n-1])*2;            }             mn = max(mn,min1);        }        cout << mn << '\n';      }    return 0;}